void solve(int CASE)
{
	int n; cin >> n;
	var a = vector<int>(n + 1);
	var st = vector<int>(n + 1);
	var ed = vector<int>(n + 1);
	int tot = 0;
	fa(i, 1, n) {
		cin >> a[i];
		if (!st[a[i]])st[a[i]] = i, tot++;
		ed[a[i]] = i;
	}

  	// 区间合并
	var p = vector<pii>();
	fa(i, 1, n)if (st[i])p.pb({ st[i], ed[i] });
	sort(all(p));
	int l = p[0].px, r = p[0].py;
	var np = vector<pii>();
	fa(i, 1, vs(p)) {
		var [x, y] = p[i];
		if (l <= y and r >= x)r = max(r, y);
		else {
			np.pb({ l,r });
			l = x, r = y;
		}
	}
	np.pb({ l,r });

  	// 构造 res 序列
	var res = vector<int>();
	for (const var& [l, r] : np) {
		var tmp = vector<int>();
		fa(i, l, r)tmp.pb(a[i]);
		sort(all(tmp));
		tmp.erase(unique(all(tmp)), tmp.end());
		reverse(all(tmp));
		res.insert(res.end(), all(tmp));
	}

  	// LIS 板子求最长单调增
	var sta = vector<int>();
	sta.pb(res[0]);
	fa(i, 1, vs(res)) {
		if (res[i] > sta.back())sta.pb(res[i]);
		else {
			var it = lower_bound(all(sta), res[i]);
			*it = res[i];
		}
	}

	cout << tot - sta.size() << endl;
	return;
}
